#include <bits/stdc++.h>
using namespace std;
struct Edge{
	int u,v,val;
}edge[100005];
bool cmp(Edge x,Edge y){
	return x.val<y.val;
}
int n,cnt,f[302],ans,sum;
int father(int x){
	return (f[x]==x?x:f[x]=father(f[x]));
}
void merge(int x,int y){
	f[father(y)]=father(x);
}
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++){
		int w;
		scanf("%d",&w);
		edge[++cnt]={0,i,w},f[i]=i;
	}
	for(int i=1;i<=n;i++)
		for(int j=1;j<=n;j++){
			int p;
			scanf("%d",&p);
			if(i<j)
				edge[++cnt]={i,j,p};
		}
	sort(edge+1,edge+cnt+1,cmp);
	for(int i=1;sum<n;i++){
		if(father(edge[i].u)!=father(edge[i].v))
			merge(edge[i].u,edge[i].v),ans+=edge[i].val,sum++;
	}
	printf("%d",ans);
	return 0;
}
